(function () { let map = new Map(); map.set("a", 1); map.set("b", 2); let e = map.entries(); let e1 = e.next(); let e2 = e.next(); let e3 = e.next(); let k = map.keys(); let v = map.values(); let seen = ""; map.forEach(function (value, key, receiver) { seen += key + "=" + value + ":" + (receiver === map) + "|"; }); return e1.value[0] + ":" + e1.value[1] + "|" + e2.value[0] + ":" + e2.value[1] + "|" + e3.done + ":" + (e3.value === undefined) + "|" + k.next().value + ":" + v.next().value + "|" + seen; })()
